// COMPLETE, COMPILABLE C code
// Uses correct I/O
// Handles all T test cases
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 1000
#define MAX_M 2000

// Structure to represent a graph
typedef struct {
    int n;
    int m;
    int **adj;
    int *indegree;
    int *ancestors;
} Graph;

// Function to create a graph
Graph* createGraph(int n, int m) {
    Graph* graph = (Graph*)malloc(sizeof(Graph));
    graph->n = n;
    graph->m = m;
    graph->adj = (int**)malloc(n * sizeof(int*));
    graph->indegree = (int*)malloc(n * sizeof(int));
    graph->ancestors = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        graph->adj[i] = (int*)malloc(m * sizeof(int));
        graph->indegree[i] = 0;
        graph->ancestors[i] = 0;
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v) {
    for (int i = 0; i < graph->m; i++) {
        if (graph->adj[u][i] == -1) {
            graph->adj[u][i] = v;
            graph->indegree[v]++;
            break;
        }
    }
}

// Function to find all ancestors of each node
void findAncestors(Graph* graph) {
    for (int i = 0; i < graph->n; i++) {
        printf("Ancestors of node %d: ", i);
        for (int j = 0; j < graph->n; j++) {
            if (graph->indegree[j] > 0) {
                printf("%d ", j);
            }
        }
        printf("\n");
    }
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    Graph* graph = createGraph(n, m);
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            graph->adj[i][j] = -1;
        }
    }
    for (int i = 0; i < m; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        addEdge(graph, u, v);
    }
    findAncestors(graph);
    return 0;
}

