        Graph graph = new Graph();
        graph.n = n;
        graph.m = m;
        graph.adj = new int[n][m];
        graph.indegree = new int[n];
        graph.ancestors = new int[n];
        return graph;
    }

    // Function to add an edge to the graph
    public static void addEdge(Graph graph, int u, int v) {
        for (int i = 0; i < graph.m; i++) {
            if (graph.adj[u][i] == 0) {
                graph.adj[u][i] = v;
                graph.indegree[v]++;
                break;
            }
        }
    }

    // Function to find all ancestors of each node
    public static void findAncestors(Graph graph) {
        for (int i = 0; i < graph.n; i++) {
            System.out.print("Ancestors of node " + i + ": ");
            for (int j = 0; j < graph.n; j++) {
                if (graph.indegree[j] > 0) {
                    System.out.print(j + " ");
                }
            }
            System.out.println();
        }
    }

    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int n = sc.nextInt();
        int m = sc.nextInt();
